class Solution {
public:
    double minTime(int n, int k, int m, vector<int>& time, vector<double>& mul) {
        sort(time.begin(), time.end());
        priority_queue<double> pq;
        double res = 0, curr_stage = 0;
        for (int i = n - 1; i >= 0; i--) {
            pq.push(time[i] * mul[(int)curr_stage % m]);
            if (pq.size() > k) {
                res += pq.top();
                pq.pop();
                curr_stage += floor(res) % m;
            }
        }
        while (!pq.empty()) {
            res += pq.top();
            pq.pop();
            curr_stage += floor(res) % m;
        }
        return res;
    }
};
